UPDATE jobs SET user_contributed_json = '{"way":"대학에서 경영학, 금융학, 경제학 등을 전공하면 취업에 유리하다.[1] 은행권 공채 또는 수시 채용에 응시하는 것이 주된 진입 경로이며, 토익·한국사능력검정 등 자격 요건을 충족해야 한다.[2] 입사 후 텔러(창구 업무)부터 시작해 여신·외환·자산관리 담당으로 커리어를 발전시킬 수 있다.[3]","overviewSalary":{"sal":"은행사무원의 평균 연봉은 약 4,200만~6,000만 원 수준이며[1], 경력·직급·은행 규모에 따라 차이가 크다.[2]","source":"커리어넷 직업백과, 워크넷(2024)"},"overviewProspect":{"main":"인터넷뱅킹·핀테크 확산으로 창구 인력은 다소 감소 추세이나[1], 디지털 금융 전문 인력 수요는 꾸준히 증가하고 있다.[2]","source":"한국고용정보원(2024)"},"trivia":"은행 텔러는 하루 평균 수백 명의 고객과 거래하며 100원 단위까지 정확히 맞춰야 한다.[1] 한국 최초의 근대 은행은 1897년 설립된 한성은행이다.[2] 국내 시중은행 직원 수는 약 10만 명을 넘으며, 이 중 절반 이상이 영업점 사무원이다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"일반적으로 오전 9시~오후 6시 근무이며 초과 근무는 적은 편이다. 다만 마감 정산과 감사 기간에는 야근이 발생할 수 있다.","socialDetail":"금융 서비스 직종으로 사회 기여도가 높이 평가되며, 대출·투자·저축을 통해 고객의 재정적 목표 달성을 직접 지원하는 보람이 있다."},"detailReady":{"curriculum":["경영학·금융학·경제학 전공 선택","토익 800점 이상 및 한국사능력검정 준비","엑셀·금융 관련 자격증(펀드투자권유대행인 등) 취득"],"recruit":["시중은행(국민·신한·하나·우리 등) 정기 공채","지방은행·인터넷은행 수시 채용","금융 공기업(기업은행·산업은행 등) 입사"],"training":["펀드투자권유대행인 자격 취득","CFP(국제공인재무설계사) 준비","은행FP·외환전문역 자격 취득"]},"sidebarJobs":["보험보상사무원","보험인수심사원(언더라이터)","신용추심원","증권사무원","출납창구사무원","금융관리자"],"sidebarMajors":["경영학과","금융·보험학과","금융경영과","경영정보학과","경영회계정보과","세무·회계학과"],"sidebarCerts":["은행텔러자격증","펀드투자권유대행인","CFP(국제공인재무설계사)","외환전문역","신용위험분석사"],"heroTags":["은행사무원","은행원","금융직","텔러","은행공채","금융취업"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"한국금융연수원","url":"https://www.kbi.or.kr/"}],"overviewSalary.sal":[{"id":4,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원 직업전망","url":"https://www.keis.or.kr/"},{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"trivia":[{"id":8,"text":"금융감독원","url":"https://www.fss.or.kr/"},{"id":9,"text":"한국금융사연구원","url":"https://www.kbhi.or.kr/"},{"id":10,"text":"은행연합회","url":"https://www.kfb.or.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"detailWlb.socialDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}]}}' WHERE id = '1765283429959345';
UPDATE jobs SET user_contributed_json = '{"way":"잠수기능원이 되려면 한국잠수협회 또는 직업훈련기관에서 교육 과정을 이수하고 잠수기능사 자격을 취득해야 한다.[1] 건설·해양 분야 잠수 업무는 산업잠수 전문 교육기관의 실습 위주 훈련이 중요하며, 자격 취득 후 해양건설사·해양공사·해군 등에 취업할 수 있다.[2] 경력을 쌓으면 잠수기사로 승급하고 현장 감독 역할을 맡을 수 있다.[3]","overviewSalary":{"sal":"연봉은 경력에 따라 3,000만~5,000만 원 수준이며[1], 위험 수당·야간 수당 등 부가 급여가 포함된다.[2]","source":"워크넷 직업정보(2024)"},"overviewProspect":{"main":"해양건설 및 수중 설비 점검 수요가 꾸준하며[1], 특수 기술직으로 고용 안정성이 비교적 높다.[2]","source":"한국고용정보원(2024)"},"trivia":"잠수기능원은 수심 40m 이하의 포화잠수 작업 시 산소·헬륨 혼합 가스를 사용해야 한다.[1] 제주 해녀는 유네스코 인류무형문화유산에 등재된 세계적 잠수 문화의 계승자이다.[2] 잠수병(감압병) 예방을 위해 잠수 후 반드시 단계적 감압 정지를 거쳐야 하며, 이를 어기면 생명이 위험할 수 있다.[3]","detailWlb":{"wlb":"낮음","social":"보통이하","wlbDetail":"해양·건설 현장 특성상 새벽 출근, 날씨에 따른 대기, 야간 작업 등이 빈번하다. 신체 위험도가 높아 정신적 긴장이 지속된다.","socialDetail":"해양 인프라 건설과 수중 구조물 유지보수를 담당하는 필수 기술직으로, 특수 직무 수행에 대한 자부심이 있으나 외부 인지도는 낮은 편이다."},"detailReady":{"curriculum":["잠수기능사 자격 과정 수료","응급처치·잠수의학 교육 이수","수중용접·절단 기초 실습"],"recruit":["해양건설사 잠수 현장직 채용","해군 잠수 특기병 입대 후 전역","수중조사·탐사 전문 업체 지원"],"training":["잠수기능사 → 잠수기사 승급","수중용접 전문 과정 이수","해양안전관리사 자격 취득"]},"sidebarJobs":["광원·채석원 및 석재절단원","잠수기어선원","전통건축기능원","점화·발파·화약관리원","철로설치·보수원"],"sidebarMajors":["산업잠수과","수산학과","건축공학과","안전공학과","토목공학과"],"sidebarCerts":["잠수기능사","잠수기사","수중용접기술자격","응급처치사(1급)","산업안전기사"],"heroTags":["잠수기능원","잠수사","산업잠수","수중작업","잠수기능사","해양건설"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"한국잠수협회","url":"https://www.kdac.or.kr/"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewSalary.sal":[{"id":4,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":5,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"trivia":[{"id":8,"text":"한국해양수산개발원","url":"https://www.kmi.re.kr/"},{"id":9,"text":"유네스코 무형문화유산","url":"https://ich.unesco.org/"},{"id":10,"text":"대한잠수기술협회","url":"https://www.kdac.or.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}],"detailWlb.socialDetail":[{"id":12,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}]}}' WHERE id = '1765283500945206';
UPDATE jobs SET user_contributed_json = '{"way":"대학에서 경영학, 산업공학, 행정학 등을 전공한 뒤[1], 일반 기업의 인사·총무·기획 부서에서 경력을 쌓는 것이 일반적인 경로이다.[2] 팀장급 이상으로 승진하거나 헤드헌팅을 통해 이직하는 경우도 많으며, MBA를 통해 역량을 강화하기도 한다.[3]","overviewSalary":{"sal":"평균 연봉은 약 5,000만~8,000만 원 수준으로 기업 규모에 따라 크게 다르며[1], 대기업 임원급은 1억 원 이상도 가능하다.[2]","source":"커리어넷 직업백과, 워크넷(2024)"},"overviewProspect":{"main":"모든 기업에 경영지원 부서가 필요해 안정적인 수요가 유지되나[1], AI·RPA 도입으로 단순 관리 업무는 자동화될 전망이다.[2]","source":"한국고용정보원(2024)"},"trivia":"경영지원관리자는 단순 행정을 넘어 M&A 실무, 리스크 관리, 전략 기획까지 총괄하기도 한다.[1] 국내 상장사 CFO(최고재무책임자) 중 상당수가 경영지원 부서 출신이다.[2] 글로벌 기업은 경영지원 관리자에게 IFRS(국제회계기준) 이해와 다국어 역량을 점점 더 필수로 요구하고 있다.[3]","detailWlb":{"wlb":"보통","social":"높음","wlbDetail":"성과 목표 달성 시기(결산·감사)에는 야근이 집중되지만, 평상시에는 비교적 규칙적인 근무가 가능하다. 재택근무 제도를 도입한 기업이 늘고 있다.","socialDetail":"조직 전체를 지원하는 역할로 다양한 부서와 협업하며, 기업 경영 성과에 직접 기여한다는 자부심이 높다."},"detailReady":{"curriculum":["경영학·행정학·산업공학 전공 선택","회계·인사·법무 관련 실무 역량 함양","ERP 시스템(SAP 등) 활용 능력 습득"],"recruit":["대기업·중견기업 경영지원팀 공채 응시","스타트업 경영지원 초기 멤버 합류","헤드헌팅 또는 경력직 이직"],"training":["공인회계사(CPA) 또는 세무사 준비","PMP(프로젝트관리전문가) 자격 취득","HRM 인사 전문가 과정 이수"]},"sidebarJobs":["금융관리자","마케팅·광고·홍보관리자","보험관리자","정부행정관리자","컴퓨터운영지원원","제조·생산관리자"],"sidebarMajors":["경영학과","경영정보학과","산업경영학과","경영정보과","산업경영과","경영회계정보과"],"sidebarCerts":["공인회계사(CPA)","경영지도사","PMP(프로젝트관리전문가)","인사관리사","ERP정보관리사"],"heroTags":["경영지원관리자","경영지원","관리자","기업경영","HR관리","총무"],"youtubeLinks":[],"_sources":{"way":[{"id":1,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":2,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"},{"id":3,"text":"한국경영자총협회","url":"https://www.kef.or.kr/"}],"overviewSalary.sal":[{"id":4,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":5,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"overviewProspect.main":[{"id":6,"text":"한국고용정보원","url":"https://www.keis.or.kr/"},{"id":7,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"trivia":[{"id":8,"text":"한국상장회사협의회","url":"https://www.klca.or.kr/"},{"id":9,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"},{"id":10,"text":"한국경영학회","url":"https://www.kams.or.kr/"}],"detailWlb.wlbDetail":[{"id":11,"text":"워크넷 직업정보","url":"https://www.work.go.kr/"}],"detailWlb.socialDetail":[{"id":12,"text":"커리어넷 직업백과","url":"https://www.career.go.kr/cnet/front/base/job/jobView.do"}]}}' WHERE id = '1765283407346795';
